+	}
+
+	// Prepare import with collision
+	incoming := &types.Issue{
+		ID:          "bd-10",
+		Title:       "MODIFIED issue",
+		Description: "Different description",
+		Status:      types.StatusInProgress,
+		Priority:    2,
+		IssueType:   types.TypeBug,
