+	// Verify remapped issue exists
+	remapped, err := testStore.GetIssue(ctx, newID)
+	if err != nil {
+		t.Fatalf("Failed to get remapped issue: %v", err)
+	}
+	if remapped == nil {
+		t.Fatal("Remapped issue not found")
